// ── PROGRESSO (localStorage) ───────────────────────────
const SAVE_KEY = 'gravitacaoZ_progresso';

function carregarProgresso(){
  const PADRAO = {
    missao1_unlocked: true,
    missao2_unlocked: false,
    missao2b_unlocked: false,
    missao3_unlocked: false,
    fase3b_completa: false,
    tem_luneta: false,
    tem_tabela_kepler: false,
    tem_principia: false,
  };
  try {
    const s = localStorage.getItem(SAVE_KEY);
    if(!s) return {...PADRAO};
    // Mesclar com padrão para garantir campos novos mesmo em saves antigos
    const salvo = JSON.parse(s);
    return {...PADRAO, ...salvo};
  } catch(e) {
    return {...PADRAO};
  }
}

function salvarProgresso(prog){
  try { localStorage.setItem(SAVE_KEY, JSON.stringify(prog)); } catch(e){}
}

// ── PERSONAGENS ────────────────────────────────────────
const PERSONAGENS = {
  "NARRADOR":           {side:'left',  bg:'#0d1a2e', bodyCol:'#334a66', headCol:'#88aacc', detail:'#aabbdd'},
  "ARISTÓTELES":        {side:'left',  bg:'#1a1000', bodyCol:'#886600', headCol:'#f5d060', detail:'#ffcc00'},
  "PTOLOMEU":           {side:'right', bg:'#130a1e', bodyCol:'#553388', headCol:'#cc88ff', detail:'#aa44cc'},
  "JOGADOR":            {side:'left',  bg:'#020818', bodyCol:'#1a44cc', headCol:'#bbcced', detail:'#00e5ff'},
  "ARISTARCO DE SAMOS": {side:'left',  bg:'#0a1a12', bodyCol:'#115533', headCol:'#44eebb', detail:'#22ffaa'},
  "NICOLAU COPÉRNICO":  {side:'left',  bg:'#1a1000', bodyCol:'#553311', headCol:'#e8a84a', detail:'#ff8800'},
  "GALILEU GALILEI":    {side:'left',  bg:'#08101e', bodyCol:'#113355', headCol:'#44aaff', detail:'#0088ff'},
  "SISTEMA":            {side:'left',  bg:'#080818', bodyCol:'#112244', headCol:'#00e5ff', detail:'#00e5ff'},
};

// ── AVATAR PIXEL ART ───────────────────────────────────
function desenharAvatarCanvas(canvasEl, quem) {
  const ax = canvasEl.getContext('2d');

  // ── Personagens com imagem real ──────────────────────
  if(_charImgs[quem] && quem !== "JOGADOR"){
    const charImg = _charImgs[quem];
    const p = PERSONAGENS[quem] || {bg:'#0a0a14', detail:'#aabbcc'};
    ax.clearRect(0,0,90,90);
    // fundo com cor do personagem
    ax.fillStyle = p.bg || '#0a0a14';
    ax.fillRect(0,0,90,90);
    ax.strokeStyle = p.detail || '#aabbcc';
    ax.lineWidth = 2;
    ax.strokeRect(1,1,88,88);
    function drawCharImg(){
      ax.imageSmoothingEnabled = true;
      ax.imageSmoothingQuality = 'high';
      ax.drawImage(charImg, 0, 0, 90, 90);
      const glow = ax.createLinearGradient(0,0,0,90);
      glow.addColorStop(0, 'rgba(255,255,255,.04)');
      glow.addColorStop(1, 'rgba(0,0,0,.22)');
      ax.fillStyle = glow;
      ax.fillRect(0,0,90,90);
    }
    if(charImg.complete && charImg.naturalWidth > 0){
      drawCharImg();
    } else {
      charImg.onload = ()=>{ desenharAvatarCanvas(canvasEl, quem); };
    }
    return;
  }

  // ── Jogador: usar imagem real ────────────────────────
  if(quem === "JOGADOR"){
    ax.clearRect(0,0,90,90);
    // fundo escuro
    ax.fillStyle='#050a14';
    ax.fillRect(0,0,90,90);
    // borda dourada interna
    ax.strokeStyle='#00e5ff';
    ax.lineWidth=2;
    ax.strokeRect(1,1,88,88);
    // desenhar imagem se carregada
    function drawPlayerImg(){
      ax.imageSmoothingEnabled = true;
      ax.imageSmoothingQuality = 'high';
      ax.drawImage(_playerImg, 0, 0, 90, 90);
      // overlay de brilho sutil
      const glow = ax.createLinearGradient(0,0,0,90);
      glow.addColorStop(0,'rgba(0,229,255,.08)');
      glow.addColorStop(1,'rgba(0,0,0,.18)');
      ax.fillStyle=glow;
      ax.fillRect(0,0,90,90);
    }
    if(_playerImg.complete && _playerImg.naturalWidth > 0){
      drawPlayerImg();
    } else {
      _playerImg.onload = ()=>{ desenharAvatarCanvas(canvasEl, quem); };
      // fallback enquanto carrega
      ax.fillStyle='#1a44cc';
      ax.fillRect(10,25,70,50);
      ax.fillStyle='#bbcced';
      ax.beginPath();ax.arc(45,20,16,0,Math.PI*2);ax.fill();
    }
    return;
  }

  const p  = PERSONAGENS[quem] || {bg:'#0a0a14', bodyCol:'#334466', headCol:'#8899bb', detail:'#aabbcc'};
  ax.clearRect(0,0,90,90);
  const bg = ax.createRadialGradient(45,45,5,45,45,52);
  bg.addColorStop(0, p.bg+'ee'); bg.addColorStop(1,'#000000');
  ax.fillStyle=bg; ax.fillRect(0,0,90,90);
  const S=2.6;
  function r(x,y,w,h,c){ax.fillStyle=c;ax.fillRect(Math.round(x*S),Math.round(y*S),Math.round(w*S),Math.round(h*S));}
  ax.fillStyle='rgba(0,0,0,.35)';
  ax.beginPath();ax.ellipse(45,82,16,4,0,0,Math.PI*2);ax.fill();
  if(quem==="ARISTÓTELES"){
    r(8,16,18,20,p.bodyCol); r(6,14,4,18,'#aa8800'); r(22,14,4,18,'#aa8800');
    r(6,12,2,6,'#cc9900'); r(24,12,2,6,'#cc9900'); r(8,35,18,2,'#cc9900');
    r(9,1,16,14,p.headCol); r(7,2,3,6,'#cc9900'); r(22,2,3,6,'#cc9900');
    r(9,13,16,3,'#886600'); r(11,6,3,3,'#553300'); r(19,6,3,3,'#553300');
    r(10,4,4,2,'#553300'); r(18,4,4,2,'#553300');
    r(24,18,4,12,'#eedd99'); r(23,17,6,2,'#ddbb77');
    r(8,36,8,4,'#cc9944'); r(18,36,8,4,'#cc9944');
  } else if(quem==="PTOLOMEU"){
    r(7,16,20,20,p.bodyCol); r(5,14,4,18,'#663399'); r(23,14,4,18,'#663399');
    ax.strokeStyle='#cc88ff';ax.lineWidth=1.2;
    ax.beginPath();ax.arc(45,60,10,0,Math.PI*2);ax.stroke();
    ax.beginPath();ax.arc(45,60,5,0,Math.PI*2);ax.stroke();
    r(10,1,14,13,p.headCol); r(8,2,3,6,'#885533'); r(22,2,3,6,'#885533');
    r(10,6,3,3,'#334455'); r(19,6,3,3,'#334455');
    ax.strokeStyle='#cc88ff';ax.lineWidth=2;
    ax.beginPath();ax.arc(16,52,8,0,Math.PI*2);ax.stroke();
    ax.beginPath();ax.moveTo(16,44);ax.lineTo(16,60);ax.moveTo(8,52);ax.lineTo(24,52);ax.stroke();
    r(8,36,8,4,'#886644'); r(18,36,8,4,'#886644');
  } else if(quem==="JOGADOR"){
    r(8,16,18,18,'#1a44cc'); r(5,18,5,14,'#0f2a88'); r(24,18,5,14,'#0f2a88');
    r(8,10,18,8,'#bbcced'); r(10,11,12,7,'rgba(160,220,255,.75)'); r(11,11,5,4,'rgba(255,255,255,.4)');
    r(8,33,16,3,'#ffaa00'); r(8,35,8,6,'#dd2211'); r(18,35,8,6,'#dd2211');
    r(6,41,10,4,'#eecc88'); r(18,41,10,4,'#eecc88'); r(25,18,4,10,'#1144bb');
  } else if(quem==="ARISTARCO DE SAMOS"){
    r(8,16,18,20,p.bodyCol); r(6,14,4,16,'#1a7744'); r(24,14,4,16,'#1a7744');
    r(9,1,16,14,p.headCol);
    ax.strokeStyle='#44eebb';ax.lineWidth=1.5;
    for(let i=0;i<5;i++){ax.beginPath();ax.arc(10+i*6,8,3,Math.PI,0);ax.stroke();}
    r(10,6,3,3,'#334455');r(19,6,3,3,'#334455');
    ax.fillStyle='#44eebb';ax.beginPath();
    for(let i=0;i<5;i++){const a=i*Math.PI*2/5-Math.PI/2;ax.lineTo(68+Math.cos(a)*8,46+Math.sin(a)*8);}
    ax.closePath();ax.fill();
    r(8,36,8,4,'#336633');r(18,36,8,4,'#336633');
  } else if(quem==="NICOLAU COPÉRNICO"){
    r(8,16,18,20,p.bodyCol); r(6,15,4,16,'#664422');r(24,15,4,16,'#664422');
    r(9,1,16,14,p.headCol); r(10,6,3,3,'#553300');r(19,6,3,3,'#553300');
    r(6,0,22,4,'#553311'); r(8,-2,18,4,'#553311');
    r(22,20,8,12,'#eedd99');r(22,20,2,12,'#cc9944');
    r(8,36,8,4,'#886644');r(18,36,8,4,'#886644');
  } else if(quem==="GALILEU GALILEI"){
    r(8,16,18,20,p.bodyCol); r(5,15,5,16,'#1a3355');r(24,15,5,16,'#1a3355');
    r(9,1,16,14,p.headCol); r(10,6,3,3,'#334455');r(19,6,3,3,'#334455');
    r(9,13,16,4,'#8899aa');
    r(24,20,10,4,'#88aacc'); r(24,19,10,2,'#4466aa'); r(33,20,4,5,'#334466');
    r(8,36,8,4,'#886644');r(18,36,8,4,'#886644');
  } else {
    r(8,16,18,20,p.bodyCol); r(9,1,16,14,p.headCol);
    r(10,6,3,3,'#334455');r(19,6,3,3,'#334455');
    r(8,36,8,4,'#445566');r(18,36,8,4,'#445566');
  }
  ax.save();ax.globalAlpha=.18;
  const grd=ax.createRadialGradient(45,45,4,45,45,44);
  grd.addColorStop(0,p.detail);grd.addColorStop(1,'transparent');
  ax.fillStyle=grd;ax.fillRect(0,0,90,90);ax.restore();
}

// ── AMBIENTE ESPACIAL ──────────────────────────────────
function criarStars(W, H, n=220){
  return Array.from({length:n},()=>({
    x:Math.random()*W, y:Math.random()*H,
    r:Math.random()*1.6+.3,
    twinkleOffset:Math.random()*Math.PI*2,
    twinkleSpeed:Math.random()*.035+.008
  }));
}

function criarNebulas(W, H){
  const nb = document.createElement('canvas');
  nb.width=W; nb.height=H;
  const nc = nb.getContext('2d');
  [{x:160,y:160,r:210,c:'rgba(80,40,180,.14)'},{x:620,y:310,r:180,c:'rgba(20,100,200,.11)'},
   {x:400,y:430,r:160,c:'rgba(180,30,100,.10)'},{x:680,y:100,r:130,c:'rgba(30,160,140,.09)'}
  ].forEach(n=>{
    const g=nc.createRadialGradient(n.x,n.y,0,n.x,n.y,n.r);
    g.addColorStop(0,n.c);g.addColorStop(1,'transparent');
    nc.fillStyle=g;nc.beginPath();nc.arc(n.x,n.y,n.r,0,Math.PI*2);nc.fill();
  });
  return nb;
}
